        ];
        yield 'html5lib test3 vertical tab in doctype name at EOF' => [
            "<!DOCTYPE a\v",
            "<!DOCTYPE a\v><html><head></head><body></body></html>",
            true,
        ];
        yield 'html5lib test3 vertical tab in no-whitespace doctype name at EOF' => [
            "<!DOCTYPEa\v",
            "<!DOCTYPE a\v><html><head></head><body></body></html>",
