        yield 'html5lib test4 mixed-case public doctype keyword preserves identifiers #1' => [
            '<!DoCtYpE HtMl PuBlIc "AbC" "XyZ">',
            '<!DOCTYPE html PUBLIC "AbC" "XyZ"><html><head></head><body></body></html>',
